import React from 'react';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    Button,
    Typography,
    Stack,
    Box,
    IconButton,
} from '@mui/material';
import CloseIcon from '@mui/icons-material/Close';
import GetAppIcon from '@mui/icons-material/GetApp';
import IosShareIcon from '@mui/icons-material/IosShare';
import AddBoxOutlinedIcon from '@mui/icons-material/AddBoxOutlined';
import BoltIcon from '@mui/icons-material/Bolt';
import OfflineBoltIcon from '@mui/icons-material/OfflineBolt';
import HomeIcon from '@mui/icons-material/Home';
import MoreVertIcon from '@mui/icons-material/MoreVert';
import { EnvConfig } from '@/constants/EnvConfig';

/**
 * Chrome / Edge / Android `beforeinstallprompt` event.
 * Not in lib.dom.d.ts yet, so declare a minimal type locally.
 */
interface BeforeInstallPromptEvent extends Event {
    readonly platforms: ReadonlyArray<string>;
    readonly userChoice: Promise<{ outcome: 'accepted' | 'dismissed'; platform: string }>;
    prompt(): Promise<void>;
}

const DISMISS_KEY = 'pwa:install:dismissedAt';
/** Don't pester users — re-show 7 days after a dismissal. */
const DISMISS_COOLDOWN_MS = 7 * 24 * 60 * 60 * 1000;
/** Wait this long after first paint before suggesting install — avoids ambushing the user. */
const SHOW_DELAY_MS = 8000;

/** Custom event name used to manually trigger the install dialog (e.g. from a
    login-page button). Bypasses the auto-snooze / standalone / iOS delay rules. */
export const PWA_INSTALL_REQUEST_EVENT = 'alumni:pwa:install:request';

/** Imperatively open the PWA install dialog. Safe to call from anywhere; if the
    component isn't mounted yet, the request is simply lost (UI affordance only). */
export function requestPwaInstall(): void {
    if (typeof window === 'undefined') return;
    window.dispatchEvent(new CustomEvent(PWA_INSTALL_REQUEST_EVENT));
}

const isStandalone = (): boolean => {
    if (typeof window === 'undefined') return false;
    if (window.matchMedia?.('(display-mode: standalone)').matches) return true;
    if (window.matchMedia?.('(display-mode: window-controls-overlay)').matches) return true;
    if (window.matchMedia?.('(display-mode: minimal-ui)').matches) return true;
    if (window.matchMedia?.('(display-mode: fullscreen)').matches) return true;
    // iOS Safari
    const navAny = window.navigator as Navigator & { standalone?: boolean };
    if (navAny.standalone === true) return true;
    // Android TWA
    if (document.referrer?.startsWith('android-app://')) return true;
    return false;
};

const isIos = (): boolean => {
    if (typeof navigator === 'undefined') return false;
    const ua = navigator.userAgent || '';
    // iPad on iOS 13+ reports "Macintosh" — also check touch points.
    const isIpadOS = ua.includes('Macintosh') && navigator.maxTouchPoints > 1;
    return /iPhone|iPad|iPod/.test(ua) || isIpadOS;
};

const recentlyDismissed = (): boolean => {
    try {
        const v = localStorage.getItem(DISMISS_KEY);
        if (!v) return false;
        const ts = parseInt(v, 10);
        if (Number.isNaN(ts)) return false;
        return Date.now() - ts < DISMISS_COOLDOWN_MS;
    } catch {
        return false;
    }
};

/**
 * Shows a one-time install dialog encouraging users to add the app to their home screen.
 *
 * Behaviour:
 *  - Skipped entirely when running as an installed PWA (display-mode standalone).
 *  - On Chromium / Android: triggered by `beforeinstallprompt`, fires the native chooser.
 *  - On iOS Safari: shows a manual "tap Share → Add to Home Screen" guide.
 *  - On other browsers without `beforeinstallprompt`: shows a generic "menu → Install"
 *    fallback so the manual trigger always produces a useful response.
 *  - Snoozes for 7 days when dismissed, effectively forever when "Don't show again" is hit.
 */
export const PWAInstallPrompt: React.FC = () => {
    const [open, setOpen] = React.useState(false);
    const [deferredPrompt, setDeferredPrompt] = React.useState<BeforeInstallPromptEvent | null>(null);
    const [iosFallback, setIosFallback] = React.useState(false);

    React.useEffect(() => {
        // Tracks whether the auto-prompt has already been shown in this
        // session. Prevents Chrome's repeat `beforeinstallprompt` events from
        // re-opening the dialog after the user closed it once.
        let autoShown = false;
        let timer: ReturnType<typeof setTimeout> | undefined;

        // ── Manual trigger ──────────────────────────────────────────────────
        // Always wired up: the user pressed an "Install app" button or menu
        // item. Bypasses the snooze / SHOW_DELAY auto-prompt rules. Still
        // no-ops when the app is already running as an installed PWA
        // (nothing to offer).
        const onManualRequest = () => {
            if (isStandalone()) return;
            // Suppress the auto-prompt (and cancel any pending timer) — the
            // user has already opened the dialog manually, so we mustn't
            // surprise them with a second popup if Chrome subsequently fires
            // `beforeinstallprompt` (clicking the button counts as engagement
            // and can satisfy the install heuristic).
            autoShown = true;
            if (timer) { clearTimeout(timer); timer = undefined; }
            if (isIos()) setIosFallback(true);
            setOpen(true);
        };
        window.addEventListener(PWA_INSTALL_REQUEST_EVENT, onManualRequest);

        // ── Auto-prompt (gated) ─────────────────────────────────────────────
        // Skipped when already installed or recently dismissed. We still
        // capture the beforeinstallprompt event unconditionally so a manual
        // trigger has a real prompt() to call later.
        const onBeforeInstall = (e: Event) => {
            e.preventDefault();
            setDeferredPrompt(e as BeforeInstallPromptEvent);
            // Only schedule the auto-open ONCE per session, and re-check
            // recentlyDismissed() at fire-time in case the user dismissed
            // before the timer elapsed (e.g. via the manual trigger).
            if (autoShown || isStandalone() || recentlyDismissed()) return;
            autoShown = true;
            if (timer) clearTimeout(timer);
            timer = setTimeout(() => {
                if (!recentlyDismissed() && !isStandalone()) setOpen(true);
            }, SHOW_DELAY_MS);
        };

        const onInstalled = () => {
            setOpen(false);
            setDeferredPrompt(null);
            try { localStorage.removeItem(DISMISS_KEY); } catch { /* ignore */ }
        };

        window.addEventListener('beforeinstallprompt', onBeforeInstall);
        window.addEventListener('appinstalled', onInstalled);

        // iOS doesn't fire beforeinstallprompt — show the manual "Add to Home
        // Screen" guide automatically (subject to the same gating).
        if (isIos() && !isStandalone() && !recentlyDismissed()) {
            autoShown = true;
            setIosFallback(true);
            timer = setTimeout(() => {
                if (!recentlyDismissed() && !isStandalone()) setOpen(true);
            }, SHOW_DELAY_MS);
        }

        return () => {
            window.removeEventListener(PWA_INSTALL_REQUEST_EVENT, onManualRequest);
            window.removeEventListener('beforeinstallprompt', onBeforeInstall);
            window.removeEventListener('appinstalled', onInstalled);
            if (timer) clearTimeout(timer);
        };
    }, []);

    const handleClose = (snooze = true) => {
        setOpen(false);
        if (snooze) {
            try { localStorage.setItem(DISMISS_KEY, String(Date.now())); } catch { /* ignore */ }
        }
    };

    const handleNeverShow = () => {
        try {
            // Effectively never — set a far-future timestamp.
            localStorage.setItem(DISMISS_KEY, String(Date.now() + 365 * 24 * 60 * 60 * 1000));
        } catch { /* ignore */ }
        setOpen(false);
    };

    const handleInstall = async () => {
        if (!deferredPrompt) return;
        try {
            await deferredPrompt.prompt();
            const choice = await deferredPrompt.userChoice;
            if (choice.outcome === 'accepted') {
                setOpen(false);
                setDeferredPrompt(null);
            } else {
                handleClose(true);
            }
        } catch {
            handleClose(true);
        }
    };

    if (!open) return null;

    const appName = EnvConfig.SiteName;

    return (
        <Dialog
            open={open}
            onClose={() => handleClose(true)}
            maxWidth='xs'
            fullWidth
            aria-labelledby='pwa-install-title'
            slotProps={{ paper: { sx: { borderRadius: 3, m: 2 } } }}
        >
            <Box
                sx={{
                    background: (t) =>
                        `linear-gradient(135deg, ${t.palette.primary.main} 0%, ${t.palette.primary.dark} 100%)`,
                    color: 'common.white',
                    px: 3,
                    pt: 3,
                    pb: 4,
                    position: 'relative',
                }}
            >
                <IconButton
                    onClick={() => handleClose(true)}
                    aria-label='Dismiss'
                    sx={{ position: 'absolute', top: 8, right: 8, color: 'rgba(255,255,255,0.85)' }}
                >
                    <CloseIcon />
                </IconButton>

                <Stack direction='row' spacing={2} sx={{ alignItems: 'center' }}>
                    <Box
                        sx={{
                            width: 56,
                            height: 56,
                            borderRadius: 2,
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            background: '#fff',
                            boxShadow: '0 4px 14px -4px rgba(0,0,0,0.25)',
                            overflow: 'hidden',
                        }}
                    >
                        {EnvConfig.SiteLogo ? (
                            <Box
                                component='img'
                                src={EnvConfig.SiteLogo}
                                alt=''
                                sx={{ width: 40, height: 40, objectFit: 'contain' }}
                            />
                        ) : (
                            <BoltIcon sx={{ color: 'primary.main', fontSize: 32 }} />
                        )}
                    </Box>
                    <Box sx={{ minWidth: 0, pr: 4, flex: 1 }}>
                        <DialogTitle
                            id='pwa-install-title'
                            sx={{ p: 0, color: 'common.white', fontWeight: 700, fontSize: '1.1rem', lineHeight: 1.25 }}
                        >
                            Install {appName}
                        </DialogTitle>
                        <Typography variant='caption' sx={{ color: 'rgba(255,255,255,0.85)', display: 'block', mt: 0.5 }}>
                            Faster access, right from your home screen.
                        </Typography>
                    </Box>
                </Stack>
            </Box>

            <DialogContent sx={{ pt: 3 }}>
                <Stack spacing={1.5} sx={{ mb: iosFallback ? 2 : 1 }}>
                    <Feature icon={<BoltIcon fontSize='small' color='primary' />} text='One-tap launch from your home screen' />
                    <Feature icon={<HomeIcon fontSize='small' color='primary' />} text='Full-screen, no browser bars' />
                    <Feature icon={<OfflineBoltIcon fontSize='small' color='primary' />} text='Works on flaky networks' />
                </Stack>

                {iosFallback && (
                    <Box
                        sx={{
                            mt: 2,
                            p: 2,
                            borderRadius: 2,
                            bgcolor: 'action.hover',
                            border: '1px dashed',
                            borderColor: 'divider',
                        }}
                    >
                        <Typography variant='subtitle2' sx={{ mb: 1 }}>
                            Install on iPhone / iPad
                        </Typography>
                        <Stack direction='row' spacing={1} sx={{ alignItems: 'center', mb: 0.5 }}>
                            <Typography variant='body2' component='span'>1.</Typography>
                            <Typography variant='body2'>Tap</Typography>
                            <IosShareIcon fontSize='small' sx={{ color: 'primary.main' }} />
                            <Typography variant='body2'>in Safari's toolbar.</Typography>
                        </Stack>
                        <Stack direction='row' spacing={1} sx={{ alignItems: 'center' }}>
                            <Typography variant='body2' component='span'>2.</Typography>
                            <Typography variant='body2'>Choose</Typography>
                            <AddBoxOutlinedIcon fontSize='small' sx={{ color: 'primary.main' }} />
                            <Typography variant='body2'><b>Add to Home Screen</b>.</Typography>
                        </Stack>
                    </Box>
                )}

                {!iosFallback && !deferredPrompt && (
                    <Box
                        sx={{
                            mt: 2,
                            p: 2,
                            borderRadius: 2,
                            bgcolor: 'action.hover',
                            border: '1px dashed',
                            borderColor: 'divider',
                        }}
                    >
                        <Typography variant='subtitle2' sx={{ mb: 0.5 }}>
                            Install via your browser menu
                        </Typography>
                        <Typography variant='body2' color='text.secondary'>
                            Click the menu button{' '}
                            <Box component='span' sx={{ display: 'inline-flex', alignItems: 'center', verticalAlign: 'middle', mx: 0.25 }}>
                                <MoreVertIcon fontSize='small' />
                            </Box>{' '}
                            in your browser toolbar and choose{' '}
                            <strong>Install {appName}</strong> or{' '}
                            <strong>Apps → Install this site</strong>.
                        </Typography>
                    </Box>
                )}
            </DialogContent>

            <DialogActions sx={{ px: 2, pb: 2, pt: 0, gap: 1, justifyContent: 'space-between', flexWrap: 'wrap' }}>
                <Button
                    onClick={handleNeverShow}
                    size='small'
                    color='inherit'
                    sx={{ textTransform: 'none', whiteSpace: 'nowrap', fontWeight: 500, color: 'text.secondary' }}
                >
                    Don't show again
                </Button>
                <Stack direction='row' spacing={1} sx={{ ml: 'auto' }}>
                    <Button
                        onClick={() => handleClose(true)}
                        color='inherit'
                        sx={{ textTransform: 'none', whiteSpace: 'nowrap', fontWeight: 500, color: 'text.secondary' }}
                    >
                        Not now
                    </Button>
                    {!iosFallback && deferredPrompt && (
                        <Button
                            onClick={handleInstall}
                            variant='contained'
                            startIcon={<GetAppIcon />}
                            sx={{ textTransform: 'none', whiteSpace: 'nowrap', fontWeight: 700, borderRadius: 2 }}
                        >
                            Install
                        </Button>
                    )}
                </Stack>
            </DialogActions>
        </Dialog>
    );
};

const Feature: React.FC<{ icon: React.ReactNode; text: string }> = ({ icon, text }) => (
    <Stack direction='row' spacing={1.5} sx={{ alignItems: 'center' }}>
        <Box
            sx={{
                width: 32,
                height: 32,
                borderRadius: 1.5,
                bgcolor: 'primary.50',
                color: 'primary.main',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0,
            }}
        >
            {icon}
        </Box>
        <Typography variant='body2'>{text}</Typography>
    </Stack>
);
